function processData(e) {
  let t = [];
  for (let l in e) {
    let a = {
        name: l,
        children: []
      },
      o = 0;
    for (let t in e[l]) o += e[l][t];
    for (let t in e[l]) e[l][t] > 1 && a.children.push({
      name: t,
      count: e[l][t]
    });
    t.push(a)
  }
  return t
}
